const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const limit = body.limit || 50;
const offset = body.offset || 0;
const status = body.status || null;

function esc(v) {
  return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'";
}

let whereClause = `WHERE s.tenant_id = ${esc(tenantId)}`;
if (status) {
  whereClause += ` AND s.status = ${esc(status)}`;
}

const sql = `WITH count_query AS (SELECT COUNT(*) as total FROM sms_campaigns ${whereClause.replace('WHERE', 'WHERE').replace(/s\./g, '')}) SELECT s.id, s.tenant_id as tenantId, s.nom, s.contenu, s.list_id as listId, s.status, s.scheduled_at as scheduledAt, s.sent_at as sentAt, s.total_envoyes as totalEnvoyes, s.total_delivered as totalDelivered, s.total_failed as totalFailed, s.created_at as createdAt, s.updated_at as updatedAt, (SELECT total FROM count_query) as total FROM sms_campaigns s ${whereClause} ORDER BY s.created_at DESC LIMIT ${limit} OFFSET ${offset}`;

return { sql };

const rows = $input.first().json || [];
const total = (Array.isArray(rows) && rows.length > 0) ? rows[0].total : 0;

const campaigns = Array.isArray(rows) ? rows.map(c => ({
  id: c.id,
  tenantId: c.tenantId,
  nom: c.nom,
  contenu: c.contenu,
  listId: c.listId,
  status: c.status,
  scheduledAt: c.scheduledAt,
  sentAt: c.sentAt,
  totalEnvoyes: c.totalEnvoyes,
  totalDelivered: c.totalDelivered,
  totalFailed: c.totalFailed,
  createdAt: c.createdAt,
  updatedAt: c.updatedAt
})) : [];

const formatted = {
  campaigns: campaigns,
  total: total,
  limit: $('02. Parser').first().json.limit,
  offset: $('02. Parser').first().json.offset
};

return formatted;
